sql:
SELECT COUNT(*) 
FROM official_assignments 
WHERE assignment_status = 'Confirmed';

SELECT rank, points
FROM league_standings
WHERE team_id = 1;

external_knowledge:
- Madejski Stadium is a football stadium in Reading, England, commonly used for league matches; 
- Team wins refer to the number of times a team emerges victorious in a match; 
- League matches refer to competitive matches played as part of a league competition, as opposed to friendly or cup matches.

sql:
SELECT certification_level, COUNT(*) AS number_of_officials
FROM match_officials
GROUP BY certification_level;

SELECT goal_difference 
FROM team_performance 
ORDER BY goal_difference DESC;

SELECT team_id, rank, points
FROM league_standings
ORDER BY rank ASC;

SELECT wins AS total_wins
FROM team_performance
WHERE team_id = 0;

external_knowledge:
; Team ID is a unique identifier for each team; 
; The team's primary uniform color is represented by 'team_color';
; A team's rank in the league is determined by its performance in matches.

sql:
